def norm_id(x):
    if x is None:
        return None
    s = str(x).strip()
    if s.startswith('#'):
        s = s[1:]
    return s

cases['accountid_norm'] = cases['accountid'].map(norm_id)
accts['Id_norm'] = accts['Id'].map(norm_id)
accts['state'] = accts['ShippingState'].astype(str).str.strip()

